def sumofsquare(n):
    c = []
    for i in range(n+1):
        c.append([0]*(n+1))
    for i in range(n+1):
        for j in range(min(i,n)+1):
            if j==0 or j==i:
                c[i][j] = 1
            else:
                c[i][j] = c[i-1][j-1] + c[i-1][j]
    sum = 0
    for i in range(n+1):
        sum += (c[n][i] * c[n][i])
    return sum

