def offeringNumber(n, templeHeight):
    # Write your code here.
    sum = 0
    for i in range(n):
        left = 0
        right = 0
        for j in range(i-1, -1, -1):
            if templeHeight[j] < templeHeight[j + 1]:
                left += 1
            else:
                break
        for j in range(i + 1, n):
            if templeHeight[j] < templeHeight[j - 1]:
                right += 1
            else:
                break
        sum += max(right, left) + 1
    return sum

