def countUnique(mat, n, m):
    rowsum = [0] * n
    colsum = [0] * m
    memset(colsum, 0, sizeof(colsum))
    memset(rowsum, 0, sizeof(rowsum))
    for i in range(0, n):
        for j in range(0, m):
            if mat[i][j] != 0:
                rowsum[i] += 1
                colsum[j] += 1
    uniquecount = 0
    for i in range(0, n):
        for j in range(0, m):
            if mat[i][j] != 0 and rowsum[i] == 1 and colsum[j] == 1:
                uniquecount += 1
    return uniquecount

